def check_even_odd(number):
    """Check if a number is even or odd using basic if-else"""
    if number % 2 == 0:
        return f"{number} is Even"
    else:
        return f"{number} is Odd"

# Test the function
print(check_even_odd(10))  # Output: 10 is Even
print(check_even_odd(7))   # Output: 7 is Odd
print(check_even_odd(0))   # Output: 0 is Even

def classify_grade(score):
    """Classify student grade based on score using elif chain"""
    if score >= 90:
        return "Grade: A - Excellent"
    elif score >= 80:
        return "Grade: B - Very Good"
    elif score >= 70:
        return "Grade: C - Good"
    elif score >= 60:
        return "Grade: D - Pass"
    else:
        return "Grade: F - Fail"

# Test the function
scores = [95, 82, 75, 62, 45]
for score in scores:
    print(classify_grade(score))
